script:
const wrapper = root_element.querySelector('#bd-dynamic-status');
const API_BASE = 'aetas_customization.aetas_customization.doctype.boutique_day_entry.boutique_day_entry.';
const VUE_PAGE_ROUTE = 'boutique-day-registe';

// --- Formatters ---
const formatCurrency = (val) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(val || 0);
const formatDate = (dStr) => frappe.datetime.str_to_user(dStr);
const formatTime = (dtStr) => {
    if (!dtStr) return '—';
    const dateObj = new Date(dtStr.replace(' ', 'T'));
    return dateObj.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
};

// --- Theme Configurations ---
const themes = {
    red: { border: '#ef4444', badgeBg: '#fef2f2', badgeColor: '#b91c1c', btnBg: '#ef4444' },
    orange: { border: '#f59e0b', badgeBg: '#fffbeb', badgeColor: '#b45309', btnBg: '#f59e0b' },
    green: { border: '#10b981', badgeBg: '#f0fdf4', badgeColor: '#047857', btnBg: '#10b981' },
    purple: { border: '#8b5cf6', badgeBg: '#f5f3ff', badgeColor: '#6d28d9', btnBg: '#8b5cf6' },
    gray: { border: '#64748b', badgeBg: '#f1f5f9', badgeColor: '#334155', btnBg: '#64748b' }
};

// --- Icons ---
const icons = {
    alert: `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path><line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>`,
    sun: `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line><line x1="1" y1="12" x2="3" y2="12"></line><line x1="21" y1="12" x2="23" y2="12"></line><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line></svg>`,
    clock: `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg>`,
    check: `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline></svg>`,
    lock: `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>`,
    btnArrow: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>`
};

// --- Bulletproof Inline Renderer ---
function renderWidget(cfg) {
    const t = themes[cfg.theme];

    let metricsHtml = '';
    if (cfg.metrics && cfg.metrics.length > 0) {
        metricsHtml = `
            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(100px, 1fr)); gap: 12px; background: #f8fafc; border-radius: 10px; padding: 16px; border: 1px solid #f1f5f9;">
                ${cfg.metrics.map(m => `
                    <div style="display: flex; flex-direction: column; gap: 4px;">
                        <span style="font-size: 0.7rem; font-weight: 700; color: #64748b; text-transform: uppercase; letter-spacing: 0.05em;">${m.label}</span>
                        <span style="font-size: 1.1rem; font-weight: 800; color: #0f172a;">${m.value}</span>
                    </div>
                `).join('')}
            </div>
        `;
    }

    wrapper.innerHTML = `
        <div style="background: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; border-top: 4px solid ${t.border}; box-shadow: 0 4px 12px -2px rgba(15, 23, 42, 0.05); padding: 24px; display: flex; flex-direction: column; gap: 20px;">

            <div style="display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid #f1f5f9; padding-bottom: 16px;">
                <div style="display: inline-flex; align-items: center; gap: 8px; padding: 6px 12px; border-radius: 20px; font-size: 0.75rem; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; background: ${t.badgeBg}; color: ${t.badgeColor};">
                    <span style="width: 8px; height: 8px; border-radius: 50%; background: ${t.border};"></span>
                    ${cfg.statusText}
                </div>
                <div style="font-size: 0.85rem; font-weight: 600; color: #64748b;">${cfg.dateText}</div>
            </div>

            <div style="display: flex; align-items: flex-start; gap: 16px;">
                <div style="width: 48px; height: 48px; border-radius: 12px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; background: ${t.badgeBg}; color: ${t.border};">
                    ${cfg.icon}
                </div>
                <div>
                    <h3 style="margin: 0 0 6px 0; font-size: 1.25rem; font-weight: 800; color: #0f172a; line-height: 1.2;">${cfg.title}</h3>
                    <p style="margin: 0; font-size: 0.95rem; color: #475569; line-height: 1.5;">${cfg.subtitle}</p>
                </div>
            </div>

            ${metricsHtml}

            <button 
                onclick="frappe.set_route('${VUE_PAGE_ROUTE}')" 
                onmouseover="this.style.opacity='0.85'" 
                onmouseout="this.style.opacity='1'" 
                style="width: 100%; padding: 12px; border-radius: 8px; border: none; font-size: 0.95rem; font-weight: 700; color: #ffffff; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px; background: ${t.btnBg}; transition: opacity 0.2s;">
                ${cfg.btnText} ${icons.btnArrow}
            </button>
        </div>
    `;
}

// --- Initialization Logic ---
frappe.call({
    method: API_BASE + 'get_current_user_boutique',
    callback: function(r) {
        const boutique = r.message;

        if (!boutique) {
            renderWidget({
                theme: 'gray',
                statusText: 'Access Restricted',
                dateText: 'System Config',
                icon: icons.lock,
                title: 'No Boutique Assigned',
                subtitle: 'Your user profile is missing the required Sales Person & Boutique links.',
                metrics: [],
                btnText: 'View Settings'
            });
            return;
        }

        frappe.call({
            method: API_BASE + 'get_day_status',
            args: { boutique: boutique },
            callback: function(res) {
                if (!res || !res.message) return;

                const prev = res.message.pending_previous;
                const today = res.message.today_entry;

                if (prev) {
                    renderWidget({
                        theme: 'red',
                        statusText: 'Action Required',
                        dateText: formatDate(prev.date),
                        icon: icons.alert,
                        title: 'Day End Pending',
                        subtitle: 'A previous shift was not closed. Data entry is locked until completed.',
                        metrics: [
                            { label: 'Started At', value: formatTime(prev.day_started_at) },
                            { label: 'Opening Cash', value: formatCurrency(prev.day_start_petty_cash) }
                        ],
                        btnText: 'Resolve Issue'
                    });
                } else if (!today || today.status === 'Draft') {
                    renderWidget({
                        theme: 'orange',
                        statusText: 'Pending Start',
                        dateText: 'Today',
                        icon: icons.sun,
                        title: 'Open the Register',
                        subtitle: 'Your shift has not been started. Please count the opening petty cash.',
                        metrics: [],
                        btnText: 'Start Shift'
                    });
                } else if (today.status === 'Day Started') {
                    renderWidget({
                        theme: 'green',
                        statusText: 'Active Shift',
                        dateText: 'Today',
                        icon: icons.clock,
                        title: 'Register is Open',
                        subtitle: 'You are currently accepting transactions for this boutique.',
                        metrics: [
                            { label: 'Started By', value: today.day_started_by.split('@')[0] },
                            { label: 'Started At', value: formatTime(today.day_started_at) },
                            { label: 'Opening Cash', value: formatCurrency(today.day_start_petty_cash) }
                        ],
                        btnText: 'Manage & End Day'
                    });
                } // STATE 4: Day Ended (Completed)
                else if (today.status === 'Day Ended') {
                    renderWidget({
                        theme: 'purple',
                        statusText: 'Completed',
                        dateText: 'Today',
                        icon: icons.check,
                        title: 'All Caught Up',
                        subtitle: 'Your shift has been successfully closed and reconciled.',
                        metrics: [
                            { label: 'Walk Ins', value: today.walk_in || 0 },
                            { label: 'New Cust.', value: today.new_customers || 0 },
                            { label: 'Exist. Cust.', value: today.existing_customers || 0 },
                            { label: 'Invoices', value: today.total_invoices || 0 },
                            { label: 'Cash Col.', value: formatCurrency(today.cash) },
                            { label: 'CC Col.', value: formatCurrency(today.cc) },
                            { label: 'Bank Col.', value: formatCurrency(today.bank_transfer) },
                            { label: 'Other', value: formatCurrency(today.other) },
                            { label: 'Closing Cash', value: formatCurrency(today.day_end_petty_cash) },
                            { label: 'Closed At', value: formatTime(today.day_ended_at) }
                        ],
                        btnText: 'View Dashboard'
                    });
                }
            }
        });
    }
});
